--
-- Name: ab_agent_memory_promotion; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.ab_agent_memory_promotion (
    id bigint NOT NULL,
    pid character varying(26) NOT NULL,
    tenant_id bigint NOT NULL,
    source_scope character varying(16) NOT NULL,
    source_memory_pid character varying(26),
    source_memory_pids jsonb,
    target_scope character varying(16) NOT NULL,
    category character varying(32) NOT NULL,
    proposed_title character varying(200),
    proposed_content text NOT NULL,
    proposed_importance integer DEFAULT 5,
    reason_code character varying(32),
    reason_detail jsonb,
    confidence_score numeric(3,2),
    similarity_score numeric(3,2),
    ai_rationale text,
    status character varying(32) DEFAULT 'DRAFT_PENDING_REVIEW'::character varying NOT NULL,
    reviewer_id bigint,
    review_comment text,
    reject_reason character varying(32),
    promoted_memory_pid character varying(26),
    shadow_started_at timestamp with time zone,
    shadow_ends_at timestamp with time zone,
    activated_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    reviewed_at timestamp with time zone,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT chk_memory_promotion_reject_reason CHECK (((reject_reason IS NULL) OR ((reject_reason)::text = ANY ((ARRAY['too_specific'::character varying, 'contains_pii'::character varying, 'outdated'::character varying, 'wrong'::character varying, 'duplicate'::character varying, 'other'::character varying])::text[])))),
    CONSTRAINT chk_memory_promotion_scope CHECK (((((source_scope)::text = 'session'::text) AND ((target_scope)::text = 'user'::text)) OR (((source_scope)::text = 'user'::text) AND ((target_scope)::text = 'tenant'::text)))),
    CONSTRAINT chk_memory_promotion_status CHECK (((status)::text = ANY ((ARRAY['DRAFT_PENDING_REVIEW'::character varying, 'REVIEWED_REJECTED'::character varying, 'PROMOTED_SHADOW'::character varying, 'ACTIVE'::character varying, 'RETRACTED'::character varying, 'DISCARDED'::character varying, 'EXPIRED'::character varying])::text[])))
);


