-- Name: TABLE ab_agent_memory_promotion; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.ab_agent_memory_promotion IS 'Memory promotion proposals and audit rows (PR-65). Status lattice: DRAFT_PENDING_REVIEW → PROMOTED_SHADOW → ACTIVE, with REVIEWED_REJECTED / RETRACTED / DISCARDED / EXPIRED as terminal states.';


