    execution_mode character varying(20) DEFAULT 'ORDERED'::character varying NOT NULL,
    failure_strategy character varying(30) DEFAULT 'FAIL_FAST'::character varying NOT NULL,
    conflict_strategy character varying(30) DEFAULT 'REJECT_ON_CONFLICT'::character varying NOT NULL,
    dedup_strategy character varying(40) DEFAULT 'BY_IDEMPOTENCY_KEY'::character varying NOT NULL,
    rules_json jsonb,
    content_hash character varying(64),
    published_by character varying(26),
    published_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CONSTRAINT chk_drt_policy_ver_conflict_strategy CHECK (((conflict_strategy)::text = ANY ((ARRAY['REJECT_ON_CONFLICT'::character varying, 'PRIORITY_WINS'::character varying, 'LAST_WRITE_WINS'::character varying, 'MERGE_IF_COMPATIBLE'::character varying])::text[]))),
    CONSTRAINT chk_drt_policy_ver_dedup_strategy CHECK (((dedup_strategy)::text = ANY ((ARRAY['NONE'::character varying, 'BY_IDEMPOTENCY_KEY'::character varying, 'BY_ACTION_TYPE_AND_TARGET'::character varying])::text[]))),
    CONSTRAINT chk_drt_policy_ver_execution_mode CHECK (((execution_mode)::text = ANY ((ARRAY['ORDERED'::character varying, 'UNORDERED'::character varying])::text[]))),
    CONSTRAINT chk_drt_policy_ver_failure_strategy CHECK (((failure_strategy)::text = ANY ((ARRAY['FAIL_FAST'::character varying, 'CONTINUE_ON_ERROR'::character varying, 'ALL_OR_NOTHING'::character varying, 'RETRY_ASYNC'::character varying, 'DEAD_LETTER'::character varying])::text[]))),
    CONSTRAINT chk_drt_policy_ver_match_mode CHECK (((match_mode)::text = ANY ((ARRAY['FIRST_MATCH'::character varying, 'COLLECT_ALL'::character varying, 'UNIQUE'::character varying, 'PRIORITY_FIRST'::character varying])::text[]))),
    CONSTRAINT chk_drt_policy_ver_phase CHECK (((phase)::text = ANY ((ARRAY['BEFORE_SUBMIT'::character varying, 'AFTER_COMMIT'::character varying, 'ASYNC_WORKER'::character varying])::text[]))),
    CONSTRAINT chk_drt_policy_ver_status CHECK (((status)::text = ANY ((ARRAY['DRAFT'::character varying, 'VALIDATED'::character varying, 'PUBLISHED'::character varying, 'DEPRECATED'::character varying, 'RETIRED'::character varying])::text[])))
);


